/* ─── rounded rect helper ────────────────────────────────────── */
function rr(
  ctx: CanvasRenderingContext2D,
  x: number, y: number,
  w: number, h: number,
  r: number,
) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.lineTo(x + w - r, y); ctx.arcTo(x + w, y, x + w, y + r, r);
  ctx.lineTo(x + w, y + h - r); ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
  ctx.lineTo(x + r, y + h); ctx.arcTo(x, y + h, x, y + h - r, r);
  ctx.lineTo(x, y + r); ctx.arcTo(x, y, x + r, y, r);
  ctx.closePath();
}

/* ─── particle type ──────────────────────────────────────────── */
interface Particle {
  x: number; y: number;
  vx: number; vy: number;
  img: HTMLImageElement;
  ready: boolean;
}

export default function TechBackground() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (window.innerWidth < 768) return;

    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let animId: number;
    let mx = -9999, my = -9999; // mouse position (off screen initially)

    /* resize */
    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener("resize", resize, { passive: true });

    /* track mouse on window so canvas stays pointer-events:none */
    const onMouse = (e: MouseEvent) => { mx = e.clientX; my = e.clientY; };
    const onLeave = () => { mx = -9999; my = -9999; };
    window.addEventListener("mousemove", onMouse, { passive: true });
    window.addEventListener("mouseleave", onLeave, { passive: true });

    /* load SVG images via Blob URLs */
    const blobUrls: string[] = [];
    const particles: Particle[] = SVGS.map(({ svg }) => {
      const blob = new Blob([svg], { type: "image/svg+xml" });
      const url = URL.createObjectURL(blob);
      blobUrls.push(url);

      const img = new Image();
      const p: Particle = {
        x: Math.random() * window.innerWidth,
        y: Math.random() * window.innerHeight,
        vx: (Math.random() - 0.5) * IDLE_V * 2,
        vy: (Math.random() - 0.5) * IDLE_V * 2,
        img,
        ready: false,
      };
      img.onload = () => { p.ready = true; };
      img.src = url;
      return p;
    });

    /* draw one card */
    const drawCard = (p: Particle) => {
      const x = p.x - CARD / 2;
      const y = p.y - CARD / 2;

      ctx.save();

      /* shadow */
      ctx.shadowColor = "rgba(0,0,0,0.18)";
      ctx.shadowBlur = 22;
      ctx.shadowOffsetY = 6;

      /* card background */
      rr(ctx, x, y, CARD, CARD, R);
      ctx.fillStyle = "rgba(255,255,255,0.82)";
      ctx.fill();

      /* border */
      ctx.shadowBlur = 0;
      ctx.shadowOffsetY = 0;
      ctx.strokeStyle = "rgba(0,0,0,0.12)";
      ctx.lineWidth = 1.5;
      ctx.stroke();

      /* logo */
      if (p.ready) {
        ctx.drawImage(p.img, x + PAD, y + PAD, LOGO, LOGO);
      }

      ctx.restore();
    };

    /* animation loop */
    const tick = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      for (const p of particles) {
        /* mouse repulsion */
        const dx = p.x - mx;
        const dy = p.y - my;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < REPEL_R && dist > 0.5) {
          const t = 1 - dist / REPEL_R;          // 0→1 as mouse gets closer
          const force = t * t * REPEL_F;
          p.vx += (dx / dist) * force;
          p.vy += (dy / dist) * force;
        }

        /* always-on wander for perpetual motion */
        p.vx += (Math.random() - 0.5) * 0.18;
        p.vy += (Math.random() - 0.5) * 0.18;

        /* damping */
        p.vx *= DAMPING;
        p.vy *= DAMPING;

        /* enforce speed floor and ceiling */
        const spd = Math.sqrt(p.vx * p.vx + p.vy * p.vy);
        if (spd > 0 && spd < IDLE_V) {
          p.vx = (p.vx / spd) * IDLE_V;
          p.vy = (p.vy / spd) * IDLE_V;
        } else if (spd > MAX_V) {
          p.vx = (p.vx / spd) * MAX_V;
          p.vy = (p.vy / spd) * MAX_V;
        }

        /* move */
        p.x += p.vx;
        p.y += p.vy;

        /* bounce off edges */
        const half = CARD / 2;
        if (p.x < half) { p.x = half; p.vx = Math.abs(p.vx); }
        if (p.x > canvas.width - half) { p.x = canvas.width - half; p.vx = -Math.abs(p.vx); }
        if (p.y < half) { p.y = half; p.vy = Math.abs(p.vy); }
        if (p.y > canvas.height - half) { p.y = canvas.height - half; p.vy = -Math.abs(p.vy); }

        drawCard(p);
      }

      animId = requestAnimationFrame(tick);
    };
    tick();

    return () => {
      cancelAnimationFrame(animId);
      window.removeEventListener("resize", resize);
      window.removeEventListener("mousemove", onMouse);
      window.removeEventListener("mouseleave", onLeave);
      blobUrls.forEach(URL.revokeObjectURL);
    };
  }, []);

  return <Canvas ref={canvasRef} aria-hidden="true" />;
}
